//autogenerated:yes
//nolint:revive,govet,errcheck
package common

import (
	"testing"

	"github.com/stretchr/testify/require"
)

func TestEnum_NAV_TAKEOFF_FLAGS(t *testing.T) {
	t.Run("zero", func(t *testing.T) {
		var e NAV_TAKEOFF_FLAGS
		e.UnmarshalText([]byte{})
		e.MarshalText()
		e.String()
	})

	t.Run("first entry", func(t *testing.T) {
		enc, err := NAV_TAKEOFF_FLAGS_HORIZONTAL_POSITION_NOT_REQUIRED.MarshalText()
		require.NoError(t, err)

		var dec NAV_TAKEOFF_FLAGS
		err = dec.UnmarshalText(enc)
		require.NoError(t, err)

		require.Equal(t, NAV_TAKEOFF_FLAGS_HORIZONTAL_POSITION_NOT_REQUIRED, dec)
	})
}
